 96	static int32_t mx_aton(const int8_t *ptr, mx_ip_addr_t *addr)
 97	{
 98	  uint32_t val = 0;
 99	  uint32_t base;
100	  int8_t c0;
101	  const int8_t *cp = ptr;
102	  uint32_t parts[4];
103	  uint32_t *pp = parts;
104	  int32_t ret = 1;
105	  int32_t done;
106	
107	  c0 = *cp;
108	  done = 0;
109	  for (;;)
110	  {
111	    /*
112	     * Collect number up to ``.''.
113	     * Values are specified as for C:
114	     * 0x=hex, 0=octal, 1-9=decimal.
115	     */
116	    if (done == 1)
117	    {
118	      break;
119	    }
120	
121	    if (!MX_ISDIGIT(c0))
122	    {
123	      ret = 0;
124	      done = 1;
125	    }
126	    else
127	    {
128	      val = 0;
129	      base = 10;
130	      if (c0 == '0')
131	      {
132	        ++cp;
133	        c0 = (int8_t) * cp;
134	        if ((c0 == (int8_t) 'x') || (c0 == (int8_t) 'X'))
135	        {
136	          base = 16;
137	          ++cp;
138	          c0 = (int8_t) * cp;
139	        }
140	        else
141	        {
142	          base = 8;
143	        }
144	      }
145	
146	      for (;;)
147	      {
148	        if (MX_ISDIGIT(c0))
149	        {
150	          val = (val * base) + (uint32_t)c0 - (uint32_t) '0';
151	          ++cp;
152	          c0 = (int8_t) * cp;
153	        }
154	        else if ((base == 16U) && MX_ISXDIGIT(c0))
155	        {
156	          val = (val << 4) | ((uint32_t)c0 + 10U - (uint32_t)(MX_ISLOWER(c0) ? 'a' : 'A'));
157	          ++cp;
158	          c0 = (int8_t) * cp;
159	        }
160	        else
161	        {
162	          break;
163	        }
164	      }
165	
166	      if (c0 == '.')
167	      {
168	        /*
169	         * Internet format:
170	         *  a.b.c.d
171	         *  a.b.c   (with c treated as 16 bits)
172	         *  a.b (with b treated as 24 bits)
173	         */
174	        if (pp >= (parts + 3))
175	        {
176	          ret = 0;
177	          done = 1;
178	        }
179	        else
180	        {
181	          *pp = val;
182	          pp++;
183	          ++cp;
184	          c0 = (int8_t) * cp;
185	        }
186	      }
187	      else
188	      {
189	        done = 1;
190	      }
191	    }
192	  }
193	  /*
194	   * Check for trailing characters.
195	   */
196	  if ((c0 != (int8_t)'\0') && (MX_ISSPACE((c0)) == false))
197	  {
198	    ret = 0;
199	  }
200	  else

  else

    /*
     * Concoct the address according to
     * the number of parts specified.
     */
  {
    switch (pp - parts + 1)
    {
      case 0:
        ret = 0;          /* initial nondigit */
        break;

      case 1:             /* a -- 32 bits */
        break;

      case 2:             /* a.b -- 8.24 bits */
        if (val > 0xffffffUL)
        {
          ret = 0;
        }
        val |= parts[0] << 24;
        break;

      case 3:             /* a.b.c -- 8.8.16 bits */
        if (val > 0xffffU)
        {
          ret = 0;
          break;
        }
        val |= (parts[0] << 24) | (parts[1] << 16);
        break;

      case 4:             /* a.b.c.d -- 8.8.8.8 bits */
        if (val > 0xffU)
        {
          ret = 0;
          break;
        }
        val |= (parts[0] << 24) | (parts[1] << 16) | (parts[2] << 8);
        break;

      default:
        ret = 0;
        break;
    }
  }

  if (ret == 1)
  {
    if (addr != NULL)
    {
      addr->addr = MX_HTONL(val);
    }
  }
  return ret;
}




static int32_t mx_aton_r(const int8_t *cp)
{
  mx_ip_addr_t val;
  int32_t       ret;
  val.addr = 0;
  if (mx_aton(cp, &val) != 0)
  {
    ret = (int32_t) val.addr;
  }
  else
  {
    ret = 0;
  }
  return (ret);
}



/**
  * @brief                   Register physical interface IO operation function
